15	// ClaudeQuotaSnapshot captures Claude's current-quota headroom as absolute
16	// token/message counts. It is written to a durable per-user cache by an
17	// asynchronous capture path and read by foreground routing consumers.
18	//
19	// The snapshot is intentionally distinct from the percentage-based
20	// QuotaSignal: foreground routing needs concrete numbers to reason about
21	// 5-hour / weekly headroom without invoking PTY capture inline.
22	type ClaudeQuotaSnapshot struct {
23		CapturedAt        time.Time               `json:"captured_at"`
24		FiveHourRemaining int                     `json:"five_hour_remaining"`
25		FiveHourLimit     int                     `json:"five_hour_limit"`
26		WeeklyRemaining   int                     `json:"weekly_remaining"`
27		WeeklyLimit       int                     `json:"weekly_limit"`
28		Windows           []harnesses.QuotaWindow `json:"windows,omitempty"`
29		Source            string                  `json:"source"` // e.g. "pty", "heuristic"
30		Account           *harnesses.AccountInfo  `json:"account,omitempty"`
31	}
32	
33	// DefaultClaudeQuotaStaleAfter is the default maximum age before a cached
34	// snapshot is considered stale and foreground routing should fall back to
35	// the safe default.
36	const DefaultClaudeQuotaStaleAfter = 15 * time.Minute
37	
38	// claudeQuotaCacheEnv lets tests override the cache file path.
39	const claudeQuotaCacheEnv = "FIZEAU_CLAUDE_QUOTA_CACHE"
40	
41	// ClaudeQuotaCachePath returns the durable location for the Claude quota
42	// cache. It resolves to $XDG_STATE_HOME/<config-dir>/claude-quota.json, or
43	// ~/.local/state/<config-dir>/claude-quota.json when XDG_STATE_HOME is unset.
44	// The FIZEAU_CLAUDE_QUOTA_CACHE env var takes precedence (primarily for
45	// tests).
46	func ClaudeQuotaCachePath() (string, error) {
47		if path := os.Getenv(claudeQuotaCacheEnv); path != "" {
48			return path, nil
49		}
50		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
51			return filepath.Join(xdg, productinfo.ConfigDir, "claude-quota.json"), nil
52		}
53		home, err := os.UserHomeDir()
54		if err != nil {
55			return "", err
56		}
57		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "claude-quota.json"), nil
58	}
59	
60	// WriteClaudeQuota atomically persists a ClaudeQuotaSnapshot to the given
61	// path. The parent directory is created if necessary. The file is written
62	// to a sibling .tmp file and renamed into place so readers never observe a
63	// partially-written snapshot. The final file mode is 0600.
64	func WriteClaudeQuota(path string, snapshot ClaudeQuotaSnapshot) error {
65		if path == "" {
66			return fmt.Errorf("claude quota cache path is empty")
67		}
68		if snapshot.CapturedAt.IsZero() {
69			snapshot.CapturedAt = time.Now().UTC()
70		} else {
71			snapshot.CapturedAt = snapshot.CapturedAt.UTC()
72		}
73	
74		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
75			return fmt.Errorf("create claude quota cache dir: %w", err)
76		}
77	
78		data, err := json.MarshalIndent(snapshot, "", "  ")
79		if err != nil {
80			return fmt.Errorf("marshal claude quota snapshot: %w", err)
81		}
82		data = append(data, '\n')
83	
84		tmpPath := path + ".tmp"
85		if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
86			return fmt.Errorf("write claude quota cache tmp: %w", err)
87		}
88		if err := os.Rename(tmpPath, path); err != nil {
89			_ = os.Remove(tmpPath)
90			return fmt.Errorf("rename claude quota cache: %w", err)
91		}
92		// Ensure final mode is 0600 in case an older file had a different mode.
93		if err := os.Chmod(path, 0o600); err != nil {
94			return fmt.Errorf("chmod claude quota cache: %w", err)
95		}
96		return nil
97	}
98	
99	// ReadClaudeQuotaFrom reads the snapshot at the given path. Returns
100	// (nil, false) if the file does not exist or cannot be decoded. Non-
101	// existence is NOT an error: foreground callers are expected to fall back
102	// to a safe default when no snapshot is present.
103	func ReadClaudeQuotaFrom(path string) (*ClaudeQuotaSnapshot, bool) {
104		data, err := os.ReadFile(path)
105		if err != nil {
106			return nil, false
107		}
108		var snap ClaudeQuotaSnapshot
109		if err := json.Unmarshal(data, &snap); err != nil {
110			return nil, false
111		}
112		return &snap, true
113	}
114	
115	// The second return value is false if no snapshot is present or cannot be
116	// decoded.
117	//
118	// Callers SHOULD check snapshot age via ClaudeQuotaSnapshotAge (or
119	// IsClaudeQuotaFresh) before trusting the values; this function does not
120	// itself enforce a TTL so that callers can report stale snapshots in
121	// diagnostic surfaces like `ddx agent doctor --routing`.
122	func ReadClaudeQuota() (*ClaudeQuotaSnapshot, bool) {
123		path, err := ClaudeQuotaCachePath()
124		if err != nil {
125			return nil, false
126		}
127		return ReadClaudeQuotaFrom(path)
128	}
129	
130	// ClaudeQuotaSnapshotAge reports the age of a snapshot relative to now.
131	// A zero or future CapturedAt yields a zero age.
132	func ClaudeQuotaSnapshotAge(snapshot *ClaudeQuotaSnapshot, now time.Time) time.Duration {
133		if snapshot == nil || snapshot.CapturedAt.IsZero() {
134			return 0
135		}
136		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
137		if age < 0 {
138			return 0
139		}
140		return age
141	}
142	
143	// IsClaudeQuotaFresh reports whether a snapshot exists and is newer than
144	// staleAfter relative to now. A nil snapshot is never fresh. A zero
145	// staleAfter falls back to DefaultClaudeQuotaStaleAfter.
146	func IsClaudeQuotaFresh(snapshot *ClaudeQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
147		if snapshot == nil || snapshot.CapturedAt.IsZero() {
148			return false
149		}
150		if staleAfter <= 0 {
151			staleAfter = DefaultClaudeQuotaStaleAfter
152		}
153		return ClaudeQuotaSnapshotAge(snapshot, now) <= staleAfter
154	}
155	
156	// ClaudeQuotaRoutingDecision summarises what foreground routing should do
157	// given the current cached snapshot.
158	type ClaudeQuotaRoutingDecision struct {
159		// PreferClaude is true when a fresh snapshot shows headroom in both the
160		// 5-hour and weekly windows. When false, routing should prefer a
161		// non-claude fallback harness.
162		PreferClaude bool
163		// SnapshotPresent is true when a snapshot was found in the cache (even
164		// if stale).
165		SnapshotPresent bool
166		// Fresh is true when the snapshot is present and newer than staleAfter.
167		Fresh bool
168		// Age is the age of the snapshot relative to now (zero when absent).
169		Age time.Duration
170		// Snapshot is the cached snapshot when present.
171		Snapshot *ClaudeQuotaSnapshot
172		// Reason describes why the decision was made (diagnostic surface).
173		Reason string
174	}
175	
176	// DecideClaudeQuotaRouting turns a cached snapshot into a routing decision
177	// for foreground callers. When the snapshot is missing or stale, the safe
178	// default is NOT to prefer claude (assume limited).
179	//
180	// A snapshot counts as "limited" when either window reports zero or
181	// negative remaining headroom.
182	func DecideClaudeQuotaRouting(snapshot *ClaudeQuotaSnapshot, now time.Time, staleAfter time.Duration) ClaudeQuotaRoutingDecision {
183		decision := ClaudeQuotaRoutingDecision{
184			Snapshot: snapshot,
185		}
186		if snapshot == nil {
187			decision.Reason = "no cached snapshot; assume limited"
188			return decision
189		}
190		decision.SnapshotPresent = true
191		decision.Age = ClaudeQuotaSnapshotAge(snapshot, now)
192		if !IsClaudeQuotaFresh(snapshot, now, staleAfter) {
193			decision.Reason = "cached snapshot is stale; assume limited"
194			return decision
195		}
196		if err := validateClaudeQuotaSnapshotForRouting(snapshot); err != nil {
197			decision.Reason = "cached snapshot is incomplete: " + err.Error() + "; assume limited"
198			return decision
199		}
200		decision.Fresh = true
201		if exhausted := exhaustedClaudeQuotaWindow(snapshot.Windows); exhausted != "" {
202			decision.Reason = "fresh snapshot reports exhausted " + exhausted + " window; assume limited"
203			return decision
204		}
205		if snapshot.FiveHourRemaining <= 0 || snapshot.WeeklyRemaining <= 0 {
206			decision.Reason = "fresh snapshot reports exhausted window; assume limited"
207			return decision
208		}
209		decision.PreferClaude = true
210		decision.Reason = "fresh snapshot has headroom"
211		return decision
212	}
213	
214	func validateClaudeQuotaSnapshotForRouting(snapshot *ClaudeQuotaSnapshot) error {
215		if snapshot == nil {
216			return fmt.Errorf("missing snapshot")
217		}
218		if strings.TrimSpace(snapshot.Source) == "" {
219			return fmt.Errorf("missing source")
220		}
221		if snapshot.Account == nil || strings.TrimSpace(snapshot.Account.PlanType) == "" {
222			return fmt.Errorf("missing account plan")
223		}
224		if snapshot.FiveHourLimit <= 0 {
225			return fmt.Errorf("invalid 5h limit")
226		}
227		if snapshot.WeeklyLimit <= 0 {
228			return fmt.Errorf("invalid weekly limit")
229		}
230		if snapshot.FiveHourRemaining < 0 || snapshot.FiveHourRemaining > snapshot.FiveHourLimit {
231			return fmt.Errorf("invalid 5h remaining")
232		}
233		if snapshot.WeeklyRemaining < 0 || snapshot.WeeklyRemaining > snapshot.WeeklyLimit {
234			return fmt.Errorf("invalid weekly remaining")
235		}
236		return nil
237	}
238	
239	func exhaustedClaudeQuotaWindow(windows []harnesses.QuotaWindow) string {
240		for _, window := range windows {
241			if !claudeQuotaWindowExhausted(window) {
242				continue
243			}
244			if strings.TrimSpace(window.LimitID) != "" {
245				return window.LimitID
246			}
247			if strings.TrimSpace(window.Name) != "" {
248				return window.Name
249			}
250			return "unknown"
251		}
252		return ""
253	}
254	
255	func claudeQuotaWindowExhausted(window harnesses.QuotaWindow) bool {
256		state := strings.ToLower(strings.TrimSpace(window.State))
257		return state == "exhausted" || window.UsedPercent >= 100
258	}
259	
260	// ReadClaudeQuotaRoutingDecision is a convenience wrapper that reads the
261	// default cache and produces a routing decision in one call. It is the
262	// entry point foreground routing should use instead of any inline PTY
263	// capture.
264	func ReadClaudeQuotaRoutingDecision(now time.Time, staleAfter time.Duration) ClaudeQuotaRoutingDecision {
265		snap, _ := ReadClaudeQuota()
266		return DecideClaudeQuotaRouting(snap, now, staleAfter)
267	}
268	
269	// IsClaudeQuotaExhaustedMessage recognizes Claude CLI quota failures that are
270	// emitted as plain text rather than structured quota data. Claude currently
271	// reports weekly exhaustion with wording like "out of extra usage", so callers
272	// must treat these strings as a hard quota signal.
273	func IsClaudeQuotaExhaustedMessage(text string) bool {
274		normalized := strings.ToLower(strings.TrimSpace(text))
275		return strings.Contains(normalized, "out of extra usage") ||
276			strings.Contains(normalized, "usage limit reached") ||
277			strings.Contains(normalized, "quota exhausted") ||
278			strings.Contains(normalized, "weekly quota") ||
279			strings.Contains(normalized, "current week") && strings.Contains(normalized, "exhaust")
280	}
281	
282	// MarkClaudeQuotaExhaustedFromMessage records a runtime Claude quota failure
283	// in the durable cache so later automatic routing avoids Claude until a fresh
284	// quota probe proves headroom again.
285	func MarkClaudeQuotaExhaustedFromMessage(text string, now time.Time) bool {
286		if !IsClaudeQuotaExhaustedMessage(text) {
287			return false
288		}
289		path, err := ClaudeQuotaCachePath()
290		if err != nil {
291			return true
292		}
293		if now.IsZero() {
294			now = time.Now()
295		}
296		snap := ClaudeQuotaSnapshot{
297			CapturedAt:        now.UTC(),
298			FiveHourLimit:     100,
299			FiveHourRemaining: 0,
300			WeeklyLimit:       100,
301			WeeklyRemaining:   0,
302			Windows: []harnesses.QuotaWindow{
303				{Name: "Current week (all models)", LimitID: "weekly-all", WindowMinutes: 10080, UsedPercent: 100, State: "exhausted"},
304				{Name: "Extra usage", LimitID: "extra", UsedPercent: 100, State: "exhausted"},
305			},
306			Source:  "runtime_error",
307			Account: &harnesses.AccountInfo{PlanType: "unknown"},
308		}
309		_ = WriteClaudeQuota(path, snap)
310		return true
311	}
312	
313	// RefreshClaudeQuotaAsync launches a background goroutine that invokes
314	// capture and writes the result to the default cache path. It returns
315	// immediately; callers never block on capture.
316	//
317	// The capture function is injected so that the durable cache layer does
318	// not depend on any specific PTY implementation. A future `ddx claude
319	// refresh-quota` subcommand can pass a real PTY-backed capture; tests can
320	// pass deterministic fakes.
321	//
322	// If capture returns an error, the cache is not touched.
323	func RefreshClaudeQuotaAsync(capture func() (ClaudeQuotaSnapshot, error)) {
324		if capture == nil {
325			return
326		}
327		go func() {
328			snap, err := capture()
329			if err != nil {
330				return
331			}
332			path, pathErr := ClaudeQuotaCachePath()
333			if pathErr != nil {
334				return
335			}
336			_ = WriteClaudeQuota(path, snap)
337		}()
338	}
