85	func captureClaudeQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, ptyquota.Result, error) {
86		cfg := quotaPTYOptions{binary: "claude"}
87		for _, opt := range opts {
88			if opt != nil {
89				opt(&cfg)
90			}
91		}
92		var windows []harnesses.QuotaWindow
93		var account *harnesses.AccountInfo
94		result, err := ptyquota.Run(ctx, ptyquota.Config{
95			HarnessName:  "claude",
96			Binary:       cfg.binary,
97			Args:         cfg.args,
98			Workdir:      cfg.workdir,
99			Env:          cfg.env,
100			Command:      "/usage\r",
101			ReadyMarkers: []string{"❯", "> "},
102			DoneWhen:     claudeUsageComplete,
103			Timeout:      timeout,
104			Size:         session.Size{Rows: 50, Cols: 220},
105			CassetteDir:  cfg.cassetteDir,
106			Quota: func(text string) (cassette.QuotaRecord, error) {
107				windows, account = parseClaudeUsageOutput(text)
108				if len(windows) == 0 {
109					return cassette.QuotaRecord{}, fmt.Errorf("no quota windows found in claude /usage output")
110				}
111				if err := validateClaudeQuotaEvidence(windows, account); err != nil {
112					return cassette.QuotaRecord{}, fmt.Errorf("incomplete claude /usage output: %w", err)
113				}
114				return quotaRecord(windows, map[string]any{"plan_type": accountPlan(account)}), nil
115			},
116		})
117		if err != nil {
118			return nil, nil, result, err
119		}
120		if len(windows) == 0 {
121			windows, account = parseClaudeUsageOutput(result.Text)
122		}
123		if len(windows) == 0 {
124			return nil, account, result, fmt.Errorf("no quota windows found in claude /usage output")
125		}
126		if err := validateClaudeQuotaEvidence(windows, account); err != nil {
127			return nil, account, result, fmt.Errorf("incomplete claude /usage output: %w", err)
128		}
129		return windows, account, result, nil
130	}
