2	
3	import (
4		"context"
5		"encoding/json"
6		"net/http"
7		"sync"
8		"time"
9	
10		"github.com/easel/fizeau/internal/discoverycache"
11		claudecache "github.com/easel/fizeau/internal/harnesses/claude"
12		codexcache "github.com/easel/fizeau/internal/harnesses/codex"
13		geminicache "github.com/easel/fizeau/internal/harnesses/gemini"
14		"github.com/easel/fizeau/internal/provider/quotaheaders"
15	)
16	
17	const (
18		// RuntimeTTL is the default cache TTL for runtime signals (ADR-012 §2).
19		RuntimeTTL = 5 * time.Minute
20		// RuntimeRefreshDeadline bounds how long a runtime signal refresh may take.
21		RuntimeRefreshDeadline = 5 * time.Second
22	
23		defaultWindowSize = 100
24		aliveCheckTimeout = 3 * time.Second
25	)
26	
27	// Store is the per-process in-memory state for runtime signal collection.
28	// It holds per-provider latency windows and the most recently observed
29	// rate-limit header signals. All methods are safe for concurrent use.
30	type Store struct {
31		mu        sync.RWMutex
32		latencies map[string]*LatencyWindow
33		headers   *headerStore
34	}
35	
36	// CollectInput describes the provider identity needed to assemble a runtime
37	// signal. Type controls the collection path; BaseURL is used by local
38	// providers for the live /v1/models check.
39	type CollectInput struct {
40		Type    string
41		BaseURL string
42	}
43	
44	// NewStore creates an empty Store ready for use.
45	func NewStore() *Store {
46		return &Store{
47			latencies: make(map[string]*LatencyWindow),
48			headers:   newHeaderStore(),
49		}
50	}
51	
52	// DefaultStore is the process-singleton Store used by the package-level
53	// RecordResponse and Collect functions.
54	var DefaultStore = NewStore()
55	
56	// RecordResponse records an HTTP response observation for a provider using the
57	// DefaultStore. providerType controls which header parser is applied
58	// ("openrouter", "anthropic", or any other value for the OpenAI parser).
59	func RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
60		DefaultStore.RecordResponse(provider, h, latency, providerType)
61	}
62	
63	// RecordResponse records an HTTP response observation. It updates both the
64	// latency window and the header signal store for the named provider.
65	func (s *Store) RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
66		win := s.latencyWindow(provider)
67		win.Record(latency)
68	
69		if h != nil {
70			now := time.Now()
71			var sig quotaheaders.Signal
72			switch providerType {
73			case "openrouter":
74				sig = quotaheaders.ParseOpenRouter(h, now)
75			case "anthropic":
76				sig = quotaheaders.ParseAnthropic(h, now)
77			default:
78				sig = quotaheaders.ParseOpenAI(h, now)
79			}
80			s.headers.record(provider, sig)
81		}
82	}
83	
84	// Collect assembles a runtime Signal for the named provider using
85	// DefaultStore.
86	func Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
87		return DefaultStore.Collect(ctx, providerName, cfg)
88	}
89	
90	// Collect assembles a runtime Signal for providerName. The cfg.Type field
91	// controls which collection path is used:
92	//
93	//   - "claude"       → existing internal/harnesses/claude/quota_cache.go
94	//   - "codex"        → existing internal/harnesses/codex/quota_cache.go
95	//   - "gemini"       → existing internal/harnesses/gemini/quota_cache.go
96	//   - "openrouter"   → most recently recorded rate-limit headers (OpenRouter parser)
97	//   - "openai", "anthropic", and unknown HTTP types → rate-limit headers
98	//   - local types    → HTTP GET /v1/models alive check (no quota concept)
99	func (s *Store) Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
100		sig := Signal{
101			Provider:   providerName,
102			Status:     StatusUnknown,
103			RecordedAt: time.Now().UTC(),
104		}
105	
106		s.mu.RLock()
107		win := s.latencies[providerName]
108		s.mu.RUnlock()
109		if win != nil {
110			sig.RecentP50Latency = win.P50()
111		}
112	
113		providerType := cfg.Type
114	
115		switch providerType {
116		case "claude":
117			collectClaudeSignal(&sig)
118		case "codex":
119			collectCodexSignal(&sig)
120		case "gemini":
121			collectGeminiSignal(&sig)
122		case "ds4", "llama-server", "omlx", "lmstudio", "lucebox", "vllm", "rapid-mlx", "ollama":
123			collectLocalSignal(ctx, cfg.BaseURL, &sig)
124		default:
125			s.collectHeaderSignal(providerName, &sig)
126		}
127	
128		return sig, nil
129	}
130	
131	// CacheSource returns the discoverycache.Source descriptor for a provider's
132	// runtime signal. The file path resolves to runtime/<provider>.json.
133	func CacheSource(providerName string) discoverycache.Source {
134		return discoverycache.Source{
135			Tier:            "runtime",
136			Name:            providerName,
137			TTL:             RuntimeTTL,
138			RefreshDeadline: RuntimeRefreshDeadline,
139		}
140	}
141	
142	// Write serializes sig and stores it in M1's runtime cache tier. The cache
143	// file lands at <cache.Root>/runtime/<sig.Provider>.json.
144	func Write(cache *discoverycache.Cache, sig Signal) error {
145		data, err := json.Marshal(sig)
146		if err != nil {
147			return err
148		}
149		src := CacheSource(sig.Provider)
150		return cache.Refresh(src, func(_ context.Context) ([]byte, error) {
151			return data, nil
152		})
153	}
154	
155	// ReadCached reads a Signal from M1's runtime cache for providerName.
156	// Returns (nil, false) when the entry is absent or cannot be decoded.
157	func ReadCached(cache *discoverycache.Cache, providerName string) (*Signal, bool) {
158		src := CacheSource(providerName)
159		result, err := cache.Read(src)
160		if err != nil || result.Data == nil {
161			return nil, false
162		}
163		var sig Signal
164		if err := json.Unmarshal(result.Data, &sig); err != nil {
165			return nil, false
166		}
167		return &sig, true
168	}
169	
170	// ---- per-provider-type collectors -------------------------------------------
171	
172	func collectClaudeSignal(sig *Signal) {
173		snap, ok := claudecache.ReadClaudeQuota()
174		if !ok || snap == nil {
175			return // StatusUnknown
176		}
177		if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
178			return // StatusUnknown; snapshot is stale
179		}
180		if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
181			sig.Status = StatusExhausted
182			zero := 0
183			sig.QuotaRemaining = &zero
184			return
185		}
186		sig.Status = StatusAvailable
187		rem := snap.FiveHourRemaining
188		sig.QuotaRemaining = &rem
189	}
190	
191	func collectCodexSignal(sig *Signal) {
192		snap, ok := codexcache.ReadCodexQuota()
193		if !ok || snap == nil {
194			return // StatusUnknown
195		}
196		if codexcache.CodexQuotaSnapshotAge(snap, time.Now()) > codexcache.DefaultCodexQuotaStaleAfter {
197			return // StatusUnknown; snapshot is stale
198		}
199		for _, w := range snap.Windows {
200			if w.UsedPercent >= 95 || w.State == "blocked" {
201				sig.Status = StatusExhausted
202				zero := 0
203				sig.QuotaRemaining = &zero
204				return
205			}
206		}
207		sig.Status = StatusAvailable
208	}
209	
210	func collectGeminiSignal(sig *Signal) {
211		snap, ok := geminicache.ReadGeminiQuota()
212		if !ok || snap == nil {
213			return // StatusUnknown
214		}
215		if geminicache.GeminiQuotaSnapshotAge(snap, time.Now()) > geminicache.DefaultGeminiQuotaStaleAfter {
216			return // StatusUnknown; snapshot is stale
217		}
218		decision := geminicache.DecideGeminiQuotaRouting(snap, time.Now(), 0)
219		if decision.PreferGemini {
220			sig.Status = StatusAvailable
221		} else {
222			sig.Status = StatusExhausted
223			zero := 0
224			sig.QuotaRemaining = &zero
225		}
226	}
227	
228	// collectHeaderSignal reads the most recently recorded rate-limit header signal
229	// for the provider and populates sig accordingly.
230	func (s *Store) collectHeaderSignal(providerName string, sig *Signal) {
231		hSig, ok := s.headers.get(providerName)
232		if !ok {
233			return // StatusUnknown; no headers observed yet
234		}
235		exhausted, retryAfter := hSig.IsExhausted(time.Now())
236		if exhausted {
237			sig.Status = StatusExhausted
238			zero := 0
239			sig.QuotaRemaining = &zero
240			if !retryAfter.IsZero() {
241				t := retryAfter
242				sig.QuotaResetAt = &t
243			}
244			return
245		}
246		sig.Status = StatusAvailable
247		switch {
248		case hSig.RemainingRequests >= 0:
249			rem := int(hSig.RemainingRequests)
250			sig.QuotaRemaining = &rem
251		case hSig.RemainingTokens >= 0:
252			rem := int(hSig.RemainingTokens)
253			sig.QuotaRemaining = &rem
254		}
255		if !hSig.ResetTime.IsZero() {
256			t := hSig.ResetTime
257			sig.QuotaResetAt = &t
258		}
259	}
260	
261	// collectLocalSignal performs an HTTP GET /v1/models alive check for local
262	// providers. Local providers have no quota concept; only StatusAvailable vs
263	// StatusDegraded is determined.
264	func collectLocalSignal(ctx context.Context, baseURL string, sig *Signal) {
265		if baseURL == "" {
266			return // StatusUnknown
267		}
268		timeoutCtx, cancel := context.WithTimeout(ctx, aliveCheckTimeout)
269		defer cancel()
270	
271		checkURL := baseURL + "/v1/models"
272		req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, checkURL, nil) // #nosec G107
273		if err != nil {
274			return // StatusUnknown; bad URL
275		}
276		resp, err := (&http.Client{}).Do(req)
277		if err != nil {
278			sig.Status = StatusDegraded
279			sig.LastErrorMsg = err.Error()
280			now := time.Now().UTC()
281			sig.LastErrorAt = &now
282			return
283		}
284		defer resp.Body.Close()
285	
286		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
287			sig.Status = StatusAvailable
288			now := time.Now().UTC()
289			sig.LastSuccessAt = &now
290		} else {
291			sig.Status = StatusDegraded
292		}
293	}
294	
295	// ---- internal helpers -------------------------------------------------------
296	
297	func (s *Store) latencyWindow(provider string) *LatencyWindow {
298		s.mu.RLock()
299		win, ok := s.latencies[provider]
300		s.mu.RUnlock()
301		if ok {
302			return win
303		}
304		s.mu.Lock()
305		defer s.mu.Unlock()
306		if win, ok = s.latencies[provider]; ok {
307			return win
308		}
309		win = NewLatencyWindow(defaultWindowSize)
310		s.latencies[provider] = win
311		return win
312	}
