597	// healthCheckRefreshClaudeQuota refreshes the Claude quota cache when
598	// the cached snapshot is older than the default refresh debounce. It is
599	// a best-effort operation: errors are silently discarded so that a
600	// claude absence does not fail HealthCheck. Under CONTRACT-004 the
601	// refresh delegates to QuotaHarness.RefreshQuota, which owns the PTY
602	// probe and cache I/O.
603	func (s *service) healthCheckRefreshClaudeQuota(ctx context.Context) {
604		qh, ok := s.harnessByName("claude").(harnesses.QuotaHarness)
605		if !ok {
606			return
607		}
608		now := time.Now()
609		if status, err := qh.QuotaStatus(ctx, now); err == nil {
610			if status.State != harnesses.QuotaUnavailable && !status.CapturedAt.IsZero() && now.Sub(status.CapturedAt) < defaultQuotaRefreshDebounce {
611				// Cache is fresh enough; skip the expensive PTY probe.
612				return
613			}
614		}
615		probeCtx, cancel := context.WithTimeout(ctx, defaultQuotaRefreshProbeTimeout)
616		defer cancel()
617		_, _ = qh.RefreshQuota(probeCtx)
618	}
