629	
630		snap, _ := codexharness.ReadCodexQuotaFrom(cachePath)
631		if snap != nil && codexharness.IsCodexQuotaFresh(snap, time.Now(), debounce) && codexQuotaCacheComplete(snap) {
632			return
633		}
