635		if sessionSnap, ok := callHealthCheckCodexSessionQuotaReader(); ok && codexSessionQuotaUsable(sessionSnap, debounce) {
636			_ = codexharness.WriteCodexQuota(cachePath, *sessionSnap)
637			return
638		}
639	
640		windows, probeErr := callHealthCheckCodexQuotaRefresher(timeout)
641		if probeErr != nil || len(windows) == 0 {
642			return
