132	func claudeQuotaSnapshotFromWindows(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) ClaudeQuotaSnapshot {
133		fiveHourUsed := usedPercentFor(windows, "session")
134		weeklyUsed := usedPercentFor(windows, "weekly-all")
135		if weeklyUsed < 0 {
136			weeklyUsed = usedPercentFor(windows, "weekly-sonnet")
137		}
138		return ClaudeQuotaSnapshot{
139			CapturedAt:        time.Now().UTC(),
140			FiveHourLimit:     100,
141			FiveHourRemaining: remainingPercent(fiveHourUsed),
142			WeeklyLimit:       100,
143			WeeklyRemaining:   remainingPercent(weeklyUsed),
144			Windows:           append([]harnesses.QuotaWindow(nil), windows...),
145			Source:            "pty",
146			Account:           account,
147		}
148	}
149	
150	func usedPercentFor(windows []harnesses.QuotaWindow, limitID string) float64 {
151		for _, window := range windows {
152			if window.LimitID == limitID {
153				return window.UsedPercent
154			}
155		}
156		return -1
157	}
158	
159	func hasQuotaWindow(windows []harnesses.QuotaWindow, limitID string) bool {
160		return usedPercentFor(windows, limitID) >= 0
161	}
162	
163	func claudeUsageComplete(text string) bool {
164		windows, _ := parseClaudeUsageOutput(text)
165		return hasQuotaWindow(windows, "session") && (hasQuotaWindow(windows, "weekly-all") || hasQuotaWindow(windows, "weekly-sonnet"))
166	}
167	
168	func validateClaudeQuotaEvidence(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) error {
169		if accountPlan(account) == "" {
170			return fmt.Errorf("missing account plan")
171		}
172		if !hasQuotaWindow(windows, "session") {
173			return fmt.Errorf("missing session window")
174		}
175		if !hasQuotaWindow(windows, "weekly-all") && !hasQuotaWindow(windows, "weekly-sonnet") {
176			return fmt.Errorf("missing weekly window")
177		}
178		return nil
179	}
180	
181	func remainingPercent(used float64) int {
182		if used < 0 {
183			return 0
184		}
185		remaining := int(math.Round(100 - used))
186		if remaining < 0 {
187			return 0
188		}
189		if remaining > 100 {
190			return 100
191		}
192		return remaining
193	}
194	
195	func quotaRecord(windows []harnesses.QuotaWindow, metadata map[string]any) cassette.QuotaRecord {
196		records := make([]map[string]any, 0, len(windows))
197		for _, window := range windows {
198			records = append(records, map[string]any{
199				"name":           window.Name,
200				"limit_id":       window.LimitID,
201				"window_minutes": window.WindowMinutes,
202				"used_percent":   window.UsedPercent,
203				"resets_at":      window.ResetsAt,
204				"state":          window.State,
205			})
206		}
207		accountClass, _ := metadata["plan_type"].(string)
208		return cassette.QuotaRecord{
209			Source:            "pty",
210			Status:            string(ptyquota.StatusOK),
211			CapturedAt:        time.Now().UTC().Format(time.RFC3339),
212			FreshnessWindow:   DefaultClaudeQuotaStaleAfter.String(),
213			StalenessBehavior: "stale quota evidence keeps Claude out of automatic routing and is treated as limited",
214			AccountClass:      accountClass,
215			Windows:           records,
216			Metadata:          metadata,
217		}
218	}
219	
220	func accountPlan(account *harnesses.AccountInfo) string {
221		if account == nil {
222			return ""
223		}
224		return account.PlanType
225	}
226	
227	func stringsJoinLines(lines []string) string {
228		out := ""
229		for i, line := range lines {
230			if i > 0 {
231				out += "\n"
232			}
233			out += line
234		}
235		return out
236	}
