13	// claudeQuotaFreshness is the constant freshness window for claude quota
14	// evidence. Mirrors DefaultClaudeQuotaStaleAfter (kept as a separate name
15	// so the CONTRACT-004 method has a stable, contract-named constant).
16	const claudeQuotaFreshness = DefaultClaudeQuotaStaleAfter
17	
18	// claudeAccountFreshness is the constant freshness window for claude
19	// account evidence. Claude embeds account info in its quota probe so the
20	// account refresh cadence matches quota.
21	const claudeAccountFreshness = DefaultClaudeQuotaStaleAfter
22	
23	// supportedLimitIDs is the stable public set of Windows[].LimitID values
24	// claude's quota probe emits. Mirrored in doc.go for human readers.
25	var supportedLimitIDs = []string{
26		"session",
27		"weekly-all",
28		"weekly-sonnet",
29		"extra",
30	}
31	
32	// supportedAliases is the stable public set of family aliases
33	// ResolveModelAlias recognizes. Mirrored in doc.go for human readers.
34	var supportedAliases = []string{"sonnet", "opus", "haiku"}
35	
36	// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
37	// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
38	// stateless wrappers — sharing the singleflight group at package scope
39	// keeps single-flight semantics correct when callers construct fresh
40	// runner instances per call (which the dispatcher does today).
41	var refreshGroup singleflight.Group
42	
43	// QuotaProbeFunc is the signature of the PTY-quota probe that
44	// Runner.RefreshQuota delegates to. Exposing it as a named type keeps
45	// the SetCaptureForTest seam decoupled from the internal ptyquota
46	// package; the test seam discards the ptyquota.Result that the live
47	// probe returns.
48	type QuotaProbeFunc func(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error)
49	
50	// captureQuotaProbe is the live PTY probe used by RefreshQuota. It is a
51	// package-level variable so tests can swap it via SetCaptureForTest
52	// without spawning the claude binary. The default delegates to
53	// captureClaudeQuotaViaPTY and discards the ptyquota.Result.
54	var captureQuotaProbe QuotaProbeFunc = func(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
55		windows, account, _, err := captureClaudeQuotaViaPTY(ctx, timeout, opts...)
56		return windows, account, err
57	}
58	
59	// SetCaptureForTest swaps the package-level PTY probe used by
60	// Runner.RefreshQuota and returns a restore function. Production code
61	// MUST NOT call this — it exists so service-level tests can inject
62	// deterministic PTY responses while exercising the real cache I/O
63	// inside Runner.refreshQuotaLocked. The call also forgets any
64	// in-flight RefreshQuota cohort so the next caller runs a fresh
65	// single-flight execution against the new probe instead of piggybacking
66	// on a prior test's probe.
67	func SetCaptureForTest(fn QuotaProbeFunc) func() {
68		prev := captureQuotaProbe
69		captureQuotaProbe = fn
70		refreshGroup.Forget("claude:refresh-quota")
71		return func() {
72			captureQuotaProbe = prev
73			refreshGroup.Forget("claude:refresh-quota")
74		}
75	}
76	
77	// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
78	// snapshot owned by this harness and projects it onto QuotaStatus. A
79	// missing or undecodable cache is reported as State=QuotaUnavailable on
80	// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
81	// reserved for call failure."
82	func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
83		if err := ctx.Err(); err != nil {
84			return harnesses.QuotaStatus{}, err
85		}
86		snap, ok := ReadClaudeQuota()
87		if !ok || snap == nil {
88			return harnesses.QuotaStatus{
89				Source:            "cache",
90				State:             harnesses.QuotaUnavailable,
91				RoutingPreference: harnesses.RoutingPreferenceUnknown,
92				Reason:            "no cached snapshot",
93			}, nil
94		}
95		return claudeQuotaStatusFromSnapshot(snap, now), nil
96	}
97	
98	// RefreshQuota implements harnesses.QuotaHarness. It probes the claude
99	// CLI via PTY unconditionally and persists the result through the
100	// harness's owned cache. Single-flight per harness: concurrent callers
101	// share one cohort and observe the just-written cached state. Probe
102	// failure (binary missing, PTY error, parse failure) is reported as
103	// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
104	func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
105		if err := ctx.Err(); err != nil {
106			return harnesses.QuotaStatus{}, err
107		}
108		v, err, _ := refreshGroup.Do("claude:refresh-quota", func() (any, error) {
109			return r.refreshQuotaLocked(ctx), nil
110		})
111		if err != nil {
112			return harnesses.QuotaStatus{}, err
113		}
114		return v.(harnesses.QuotaStatus), nil
115	}
116	
117	// refreshQuotaLocked is the single-flight critical section. It probes
118	// PTY, writes the cache on success, and returns the projected status.
119	// Probe failure is folded into State=QuotaUnavailable.
120	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
121		now := time.Now()
122		timeout := claudeQuotaFreshness
123		if deadline, ok := ctx.Deadline(); ok {
124			remaining := time.Until(deadline)
125			if remaining > 0 && remaining < timeout {
126				timeout = remaining
127			}
128		}
129		var opts []QuotaPTYOption
130		if r.Binary != "" {
131			opts = append(opts, WithQuotaPTYCommand(r.Binary))
132		}
133		windows, account, err := captureQuotaProbe(ctx, timeout, opts...)
134		if err != nil {
135			state := harnesses.QuotaUnavailable
136			reason := err.Error()
137			if strings.Contains(strings.ToLower(reason), "not found in path") {
138				state = harnesses.QuotaUnauthenticated
139			}
140			return harnesses.QuotaStatus{
141				Source:            "pty",
142				CapturedAt:        now.UTC(),
143				State:             state,
144				RoutingPreference: harnesses.RoutingPreferenceUnknown,
145				Reason:            reason,
146			}
147		}
148		snap := claudeQuotaSnapshotFromWindows(windows, account)
149		if path, pathErr := ClaudeQuotaCachePath(); pathErr == nil {
150			_ = WriteClaudeQuota(path, snap)
151		}
152		return claudeQuotaStatusFromSnapshot(&snap, now)
153	}
