199	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
200	// harnesses.ErrAliasNotResolvable when the supplied family is not a
201	// recognized claude alias or when the supplied discovery snapshot has
202	// no concrete model matching the family.
203	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
204		normalized := strings.ToLower(strings.TrimSpace(family))
205		if !isSupportedClaudeAlias(normalized) {
206			return "", harnesses.ErrAliasNotResolvable
207		}
208		resolved := ResolveClaudeFamilyAlias(normalized, snapshot)
209		if resolved == "" {
