19	// Fallback only: unpinned runs resolve through model discovery first.
20	const fallbackDefaultModel = "claude-sonnet-4-6"
21	
22	// Default size for the per-Execute event channel buffer. Large enough that
23	// fast tool-call bursts (claude can emit dozens of blocks per turn) do not
24	// stall the parser, small enough to bound memory in pathological streams.
25	const defaultEventBuffer = 64
26	
27	// Default idle/stream timeout when ExecuteRequest leaves IdleTimeout unset.
28	// Mirrors the wall-clock cap the DDx-side runner used historically; an
29	// explicit ExecuteRequest.Timeout still wins.
30	const defaultIdleTimeout = 0 // 0 = no idle cap; rely on Timeout / ctx.
31	
32	// Runner is the subprocess-backed claude harness. It launches the claude
33	// CLI in stream-json mode, parses each line into harness Events, and emits
34	// a final Event when the subprocess exits. On ctx.Done(), the subprocess
35	// (and any forked children belonging to its process group) is signalled
36	// SIGTERM and reaped so PTY/tool children don't outlive the request.
37	type Runner struct {
38		// Binary is the absolute path to the claude executable. When empty the
39		// runner resolves "claude" via PATH at Execute time.
40		Binary string
41	
42		// BaseArgs is prepended to the per-request argument list; callers use
43		// it to pin a consistent invocation profile (e.g. ["--print", "-p",
44		// "--output-format", "stream-json", "--verbose"]).
45		BaseArgs []string
46	
47		// PromptMode controls how the prompt is delivered to claude:
48		//   "stdin" (default) — prompt is piped on stdin
49		//   "arg"             — prompt is appended as the final positional argument
50		PromptMode string
51	
52		// EventBuffer overrides the per-Execute channel buffer size. Zero
53		// selects defaultEventBuffer.
54		EventBuffer int
55	
56		// DiscoveryCache overrides model/reasoning discovery evidence in tests.
57		DiscoveryCache *harnesses.ModelDiscoveryCache
58	}
59	
60	// Info returns identity + capability metadata for this harness.
61	//
62	// Path is best-effort: the runner reports Binary if set, otherwise looks
63	// up "claude" on PATH. Available tracks whether the lookup succeeded so
64	// callers can show a useful error in `ddx agent list` without invoking
65	// HealthCheck synchronously.
66	func (r *Runner) Info() harnesses.HarnessInfo {
67		info := harnesses.HarnessInfo{
68			Name:                 "claude",
69			Type:                 "subprocess",
70			IsLocal:              false,
71			IsSubscription:       true,
72			AutoRoutingEligible:  true,
73			ExactPinSupport:      true,
74			DefaultModel:         harnesses.ResolveRunnerModel("claude", modelcatalog.SurfaceClaudeCode, "", fallbackDefaultModel).ResolvedModel,
75			SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
76			SupportedReasoning:   []string{"low", "medium", "high", "xhigh", "max"},
77			CostClass:            "medium",
78		}
79		path := r.Binary
80		if path == "" {
81			if resolved, err := osexec.LookPath("claude"); err == nil {
82				path = resolved
83			}
84		}
85		if path != "" {
86			info.Path = path
87			info.Available = true
88		} else {
89			info.Error = "claude binary not found in PATH"
90		}
91		return info
92	}
93	
94	// HealthCheck verifies the claude binary resolves on PATH (or at the
95	// configured Binary). It does NOT invoke the binary so it stays cheap and
96	// safe to call from request hot paths. A future extension can probe quota
97	// state via the cache layer.
98	func (r *Runner) HealthCheck(ctx context.Context) error {
99		if err := ctx.Err(); err != nil {
100			return err
101		}
102		path := r.Binary
103		if path == "" {
104			resolved, err := osexec.LookPath("claude")
105			if err != nil {
106				return fmt.Errorf("claude binary not found: %w", err)
107			}
108			path = resolved
109		}
110		st, err := os.Stat(path)
111		if err != nil {
112			return fmt.Errorf("stat claude binary: %w", err)
113		}
114		if st.IsDir() {
115			return fmt.Errorf("claude binary path is a directory: %s", path)
116		}
117		return nil
118	}
119	
120	// Execute runs one resolved request through the claude CLI and emits
121	// stream-derived events on the returned channel. The channel is closed
122	// once a final event has been emitted. PTY/orphan children are reaped on
123	// ctx.Done(). If the CLI rejects stream-json flags (older build), the
124	// runner falls back to a buffered legacy invocation and emits a single
125	// text_delta + final from the buffered output.
126	func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
127		binary := r.Binary
128		if binary == "" {
129			resolved, err := osexec.LookPath("claude")
130			if err != nil {
131				return nil, fmt.Errorf("claude binary not found: %w", err)
132			}
133			binary = resolved
134		}
135	
136		bufSize := r.EventBuffer
137		if bufSize <= 0 {
138			bufSize = defaultEventBuffer
139		}
140	
141		// Channel returned to the caller; the goroutine below owns closing it.
142		out := make(chan harnesses.Event, bufSize)
143	
144		go r.run(ctx, binary, req, out)
145		return out, nil
146	}
147	
148	// run is the per-Execute goroutine: starts claude, streams events, and
149	// guarantees a final event + channel close on every termination path.
150	func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
151		defer close(out)
152	
153		start := time.Now()
154		var seq int64
155	
156		// First attempt: stream-json invocation.
157		agg, exitCode, stderr, runErr, status := r.runStreaming(ctx, binary, req, out, &seq)
158	
159		// Fallback path: claude rejected the stream-json flags. Retry with the
160		// legacy buffered --print/-p/--output-format=json invocation. We surface
161		// the legacy output as a single text_delta so consumers still receive
162		// the model's final text.
163		if status == "failed" && exitCode == 2 && claudeStreamArgsUnsupported(stderr) {
164			// Reset the aggregate so legacy output drives final event.
165			agg, exitCode, stderr, runErr, status = r.runLegacy(ctx, binary, req, out, &seq)
166		}
167	
168		// Emit the final event regardless of outcome so downstream consumers
169		// always see a terminator. Errors during emit are non-fatal — the
170		// channel close still signals end-of-stream.
171		final := harnesses.FinalData{
172			Status:     status,
173			ExitCode:   exitCode,
174			DurationMS: time.Since(start).Milliseconds(),
175		}
176		reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "claude", req.Reasoning)
177		if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
178			final.Reasoning = &reasoningResolution
179		}
180		quotaMessage := claudeQuotaMessage(stderr, runErr, agg)
181		if quotaMessage != "" {
182			MarkClaudeQuotaExhaustedFromMessage(quotaMessage, time.Now())
183		}
184		if runErr != nil && status != "success" {
185			final.Error = runErr.Error()
186		} else if stderr != "" && status != "success" {
187			final.Error = trimErrorBlob(stderr)
188		}
189		if quotaMessage != "" && status != "success" {
190			final.Error = "claude quota exhausted: " + trimErrorBlob(quotaMessage)
191		}
192		if agg != nil {
193			final.FinalText = agg.FinalText
194			final.Usage, final.Warnings = harnesses.ResolveFinalUsage(agg.UsageSources)
195			if agg.CostUSD > 0 {
196				final.CostUSD = agg.CostUSD
197			}
198		}
199	
200		finalRaw, err := json.Marshal(final)
201		if err != nil {
202			// Defensive: marshal can only fail on programmer error here.
203			finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
204		}
205		ev := harnesses.Event{
206			Type:     harnesses.EventTypeFinal,
207			Sequence: seq,
208			Time:     time.Now().UTC(),
209			Metadata: req.Metadata,
210			Data:     finalRaw,
211		}
212		select {
213		case out <- ev:
214		case <-time.After(time.Second):
215			// Caller has stopped consuming; drop and close.
216		}
217	}
218	
219	func claudeQuotaMessage(stderr string, runErr error, agg *streamAggregate) string {
220		for _, candidate := range []string{
221			stderr,
222			func() string {
223				if agg == nil {
224					return ""
225				}
226				return agg.FinalText
227			}(),
228			func() string {
229				if runErr == nil {
230					return ""
231				}
232				return runErr.Error()
233			}(),
234		} {
235			if IsClaudeQuotaExhaustedMessage(candidate) {
236				return candidate
237			}
238		}
239		return ""
240	}
241	
242	// runStreaming drives the stream-json path: launches claude with the
243	// configured BaseArgs, pipes stdout through the parser, and returns the
244	// aggregated stream state plus exit metadata.
245	func (r *Runner) runStreaming(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
246		base := r.BaseArgs
247		if base == nil {
248			base = []string{"--print", "-p", "--verbose", "--output-format", "stream-json"}
249		}
250		args := r.buildArgs(base, req)
251	
252		promptMode := r.PromptMode
253		if promptMode == "" {
254			promptMode = "arg"
255		}
256		if promptMode == "arg" && req.Prompt != "" {
257			args = append(args, req.Prompt)
258		}
259	
260		runCtx, cancel := context.WithCancel(ctx)
261		defer cancel()
262	
263		cmd := osexec.CommandContext(runCtx, binary, args...)
264		if req.WorkDir != "" {
265			cmd.Dir = req.WorkDir
266		}
267		if promptMode != "arg" {
268			cmd.Stdin = strings.NewReader(req.Prompt)
269		}
270		// Put the child in its own process group so we can signal the entire
271		// tree (PTY/tool children included) on ctx.Done().
272		setProcessGroup(cmd)
273	
274		stdoutPipe, err := cmd.StdoutPipe()
275		if err != nil {
276			return nil, -1, "", err, "failed"
277		}
278		stderrPipe, err := cmd.StderrPipe()
279		if err != nil {
280			return nil, -1, "", err, "failed"
281		}
282	
283		if err := cmd.Start(); err != nil {
284			return nil, -1, "", err, "failed"
285		}
286	
287		progressLog, _ := harnesses.OpenProgressLog(req.SessionLogDir, req.SessionID, "claude")
288		if progressLog != nil {
289			defer progressLog.Close()
290		}
291		modelResolution := harnesses.ResolveRunnerModelWithCache(r.DiscoveryCache, "claude", modelcatalog.SurfaceClaudeCode, req.Model, fallbackDefaultModel)
292		reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "claude", req.Reasoning)
293		if harnesses.ShouldEmitRunnerDefaultResolution(modelResolution) {
294			ev := harnesses.RunnerDefaultResolutionEvent(modelResolution, req.Metadata, seq)
295			harnesses.WriteProgressEvent(progressLog, ev)
296			select {
297			case out <- ev:
298			case <-ctx.Done():
299				return nil, -1, "", ctx.Err(), "cancelled"
300			}
301		}
302		if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
303			harnesses.LogRunnerReasoningWarning(reasoningResolution)
304			ev := harnesses.RunnerReasoningResolutionEvent(reasoningResolution, req.Metadata, seq)
305			harnesses.WriteProgressEvent(progressLog, ev)
306			select {
307			case out <- ev:
308			case <-ctx.Done():
309				return nil, -1, "", ctx.Err(), "cancelled"
310			}
311		}
312	
313		// Tee stdout into the parser and (optionally) into the progress log.
314		parserReader, parserWriter := io.Pipe()
315		parseDone := make(chan struct{})
316		var parseAgg *streamAggregate
317		var parseErr error
318		// Wrap out so we can also mirror events to disk as JSONL. mirrorDone
319		// signals that the mirror goroutine has fully drained — must be awaited
320		// before run() lets defer close(out) fire, otherwise we get a close vs.
321		// chansend race when the mirror is mid-send to dst.
322		mirrored, mirrorDone := harnesses.MirrorEvents(out, progressLog, ctx)
323		go func() {
324			defer close(parseDone)
325			defer close(mirrored) // releases the mirror goroutine's range loop
326			parseAgg, parseErr = parseClaudeStream(runCtx, parserReader, mirrored, req.Metadata, seq)
327		}()
328	
329		stdoutDone := make(chan struct{})
330		go func() {
331			defer close(stdoutDone)
332			_, _ = io.Copy(parserWriter, stdoutPipe)
333			_ = parserWriter.Close()
334		}()
335	
336		var stderrBuf strings.Builder
337		stderrDone := make(chan struct{})
338		go func() {
339			defer close(stderrDone)
340			_, _ = io.Copy(&stringBuilderWriter{&stderrBuf}, stderrPipe)
341		}()
342	
343		// Wall-clock / idle timeout: if Timeout is set, cancel after it fires.
344		var timedOut bool
345		if req.Timeout > 0 {
346			stop := make(chan struct{})
347			go func() {
348				select {
349				case <-stop:
350				case <-time.After(req.Timeout):
351					timedOut = true
352					cancel()
353				}
354			}()
355			defer close(stop)
356		}
357	
358		// Cancellation watchdog: when the parent ctx is done, signal the
359		// process group and let cmd.Wait() pick up the exit. The defer on
360		// runCtx already calls cancel; this goroutine just escalates to
361		// SIGTERM/SIGKILL on the group so PTY children don't survive.
362		cancelDone := make(chan struct{})
363		go func() {
364			defer close(cancelDone)
365			select {
366			case <-ctx.Done():
367				killProcessGroup(cmd)
368				select {
369				case <-stdoutDone:
370				case <-time.After(2 * time.Second):
371					forceKillProcessGroup(cmd)
372				}
373			case <-stdoutDone:
374			}
375		}()
376	
377		<-stdoutDone
378		<-stderrDone
379		<-parseDone
380		<-mirrorDone
381		runErr = cmd.Wait()
382		<-cancelDone
383		stderr = stderrBuf.String()
384	
385		// Classify exit.
386		switch {
387		case timedOut:
388			return parseAgg, -1, stderr, context.DeadlineExceeded, "timed_out"
389		case ctx.Err() != nil && errors.Is(ctx.Err(), context.Canceled):
390			return parseAgg, -1, stderr, ctx.Err(), "cancelled"
391		case ctx.Err() != nil && errors.Is(ctx.Err(), context.DeadlineExceeded):
392			return parseAgg, -1, stderr, ctx.Err(), "timed_out"
393		case runErr != nil:
394			ec := -1
395			var exitErr *osexec.ExitError
396			if errors.As(runErr, &exitErr) {
397				ec = exitErr.ExitCode()
398			}
399			return parseAgg, ec, stderr, runErr, "failed"
400		}
401		if parseErr != nil && !errors.Is(parseErr, context.Canceled) {
402			return parseAgg, 0, stderr, parseErr, "failed"
403		}
404		if parseAgg != nil && parseAgg.IsError {
405			return parseAgg, 0, stderr, errors.New("claude reported is_error=true"), "failed"
406		}
407		return parseAgg, 0, stderr, nil, "success"
408	}
409	
410	// runLegacy invokes the legacy buffered claude path used when the CLI
411	// rejected stream-json flags. It surfaces the captured stdout as a single
412	// text_delta event so callers still receive the model's text.
413	func (r *Runner) runLegacy(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (*streamAggregate, int, string, error, string) {
414		args := r.buildArgs([]string{"--print", "-p", "--output-format", "json"}, req)
415		promptMode := r.PromptMode
416		if promptMode == "" {
417			promptMode = "arg"
418		}
419		if promptMode == "arg" && req.Prompt != "" {
420			args = append(args, req.Prompt)
421		}
422	
423		runCtx, cancel := context.WithCancel(ctx)
424		defer cancel()
425	
426		cmd := osexec.CommandContext(runCtx, binary, args...)
427		if req.WorkDir != "" {
428			cmd.Dir = req.WorkDir
429		}
430		if promptMode != "arg" {
431			cmd.Stdin = strings.NewReader(req.Prompt)
432		}
433		setProcessGroup(cmd)
434	
435		stdoutBytes, err := cmd.Output()
436		stderrBytes := ""
437		var exitErr *osexec.ExitError
438		if errors.As(err, &exitErr) {
439			stderrBytes = string(exitErr.Stderr)
440		}
441	
442		if err != nil {
443			ec := -1
444			if exitErr != nil {
445				ec = exitErr.ExitCode()
446			}
447			return nil, ec, stderrBytes, err, "failed"
448		}
449	
450		text := strings.TrimSpace(string(stdoutBytes))
451		if text != "" {
452			raw, _ := json.Marshal(harnesses.TextDeltaData{Text: text})
453			ev := harnesses.Event{
454				Type:     harnesses.EventTypeTextDelta,
455				Sequence: *seq,
456				Time:     time.Now().UTC(),
457				Metadata: req.Metadata,
458				Data:     raw,
459			}
460			*seq++
461			select {
462			case out <- ev:
463			case <-ctx.Done():
464				return nil, 0, stderrBytes, ctx.Err(), "cancelled"
465			}
466		}
467		return &streamAggregate{FinalText: text}, 0, stderrBytes, nil, "success"
468	}
469	
470	func (r *Runner) buildArgs(base []string, req harnesses.ExecuteRequest) []string {
471		args := append([]string{}, base...)
472		modelResolution := harnesses.ResolveRunnerModelWithCache(r.DiscoveryCache, "claude", modelcatalog.SurfaceClaudeCode, req.Model, fallbackDefaultModel)
473		reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "claude", req.Reasoning)
474		switch req.Permissions {
475		case "supervised":
476			args = append(args, "--permission-mode", "default")
477		case "unrestricted":
478			args = append(args, "--permission-mode", "bypassPermissions", "--dangerously-skip-permissions")
479		}
480		if modelResolution.ResolvedModel != "" {
481			args = append(args, "--model", modelResolution.ResolvedModel)
482		}
483		if value := reasoningResolution.ResolvedReasoning; value != "" {
484			args = append(args, "--effort", value)
485		}
486		return args
487	}
488	
489	// stringBuilderWriter adapts *strings.Builder to io.Writer.
490	type stringBuilderWriter struct {
491		sb *strings.Builder
492	}
493	
494	func (w *stringBuilderWriter) Write(p []byte) (int, error) {
495		return w.sb.Write(p)
496	}
497	
498	// trimErrorBlob caps stderr for inclusion in the final event so a runaway
499	// error log doesn't bloat the channel payload.
500	func trimErrorBlob(s string) string {
501		const max = 2048
502		s = strings.TrimSpace(s)
503		if len(s) > max {
504			return s[:max] + "...(truncated)"
505		}
506		return s
507	}
508	
509	// setProcessGroup configures cmd to start in its own process group on
510	// POSIX. Implemented in a build-tagged file for cross-platform support.
511	func setProcessGroup(cmd *osexec.Cmd) {
512		if cmd.SysProcAttr == nil {
513			cmd.SysProcAttr = &syscall.SysProcAttr{}
514		}
515		setProcessGroupAttr(cmd.SysProcAttr)
516	}
517

