package claude

import (
	"context"
	"fmt"
	"math"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/ptyquota"
	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
)

type quotaPTYOptions struct {
	binary      string
	args        []string
	workdir     string
	env         []string
	cassetteDir string
}

type QuotaPTYOption func(*quotaPTYOptions)

func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.binary = binary
		opts.args = append([]string(nil), args...)
	}
}

func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.workdir = workdir
	}
}

func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.env = append([]string(nil), env...)
	}
}

func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.cassetteDir = dir
	}
}

func readClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
	windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
	return windows, account, err
}

func refreshClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (claudeQuotaSnapshot, error) {
	windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
	if err != nil {
		return claudeQuotaSnapshot{}, err
	}
	return claudeQuotaSnapshotFromWindows(windows, account), nil
}

func readClaudeQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
	reader, err := cassette.Open(dir)
	if err != nil {
		return nil, nil, err
	}
	text := reader.Final().FinalText
	if text == "" {
		frames := reader.Frames()
		if len(frames) > 0 {
			text = stringsJoinLines(frames[len(frames)-1].Text)
		}
	}
	windows, account := parseClaudeUsageOutput(text)
	if len(windows) == 0 {
		return nil, account, fmt.Errorf("no quota windows found in claude quota cassette")
	}
	if err := validateClaudeQuotaEvidence(windows, account); err != nil {
		return nil, account, fmt.Errorf("incomplete claude quota cassette: %w", err)
	}
	return windows, account, nil
}

func captureClaudeQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, ptyquota.Result, error) {
	cfg := quotaPTYOptions{binary: "claude"}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	var windows []harnesses.QuotaWindow
	var account *harnesses.AccountInfo
	result, err := ptyquota.Run(ctx, ptyquota.Config{
		HarnessName:  "claude",
		Binary:       cfg.binary,
		Args:         cfg.args,
		Workdir:      cfg.workdir,
		Env:          cfg.env,
		Command:      "/usage\r",
		ReadyMarkers: []string{"❯", "> "},
		DoneWhen:     claudeUsageComplete,
		Timeout:      timeout,
		Size:         session.Size{Rows: 50, Cols: 220},
		CassetteDir:  cfg.cassetteDir,
		Quota: func(text string) (cassette.QuotaRecord, error) {
			windows, account = parseClaudeUsageOutput(text)
			if len(windows) == 0 {
				return cassette.QuotaRecord{}, fmt.Errorf("no quota windows found in claude /usage output")
			}
			if err := validateClaudeQuotaEvidence(windows, account); err != nil {
				return cassette.QuotaRecord{}, fmt.Errorf("incomplete claude /usage output: %w", err)
			}
			return quotaRecord(windows, map[string]any{"plan_type": accountPlan(account)}), nil
		},
	})
	if err != nil {
		return nil, nil, result, err
	}
	if len(windows) == 0 {
		windows, account = parseClaudeUsageOutput(result.Text)
	}
	if len(windows) == 0 {
		return nil, account, result, fmt.Errorf("no quota windows found in claude /usage output")
	}
	if err := validateClaudeQuotaEvidence(windows, account); err != nil {
		return nil, account, result, fmt.Errorf("incomplete claude /usage output: %w", err)
	}
	return windows, account, result, nil
}

func claudeQuotaSnapshotFromWindows(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) claudeQuotaSnapshot {
	fiveHourUsed := usedPercentFor(windows, "session")
	weeklyUsed := usedPercentFor(windows, "weekly-all")
	if weeklyUsed < 0 {
		weeklyUsed = usedPercentFor(windows, "weekly-sonnet")
	}
	return claudeQuotaSnapshot{
		CapturedAt:        time.Now().UTC(),
		FiveHourLimit:     100,
		FiveHourRemaining: remainingPercent(fiveHourUsed),
		WeeklyLimit:       100,
		WeeklyRemaining:   remainingPercent(weeklyUsed),
		Windows:           append([]harnesses.QuotaWindow(nil), windows...),
		Source:            "pty",
		Account:           account,
	}
}

func usedPercentFor(windows []harnesses.QuotaWindow, limitID string) float64 {
	for _, window := range windows {
		if window.LimitID == limitID {
			return window.UsedPercent
		}
	}
	return -1
}

func hasQuotaWindow(windows []harnesses.QuotaWindow, limitID string) bool {
	return usedPercentFor(windows, limitID) >= 0
}

func claudeUsageComplete(text string) bool {
	windows, _ := parseClaudeUsageOutput(text)
	return hasQuotaWindow(windows, "session") && (hasQuotaWindow(windows, "weekly-all") || hasQuotaWindow(windows, "weekly-sonnet"))
}

func validateClaudeQuotaEvidence(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) error {
	if accountPlan(account) == "" {
		return fmt.Errorf("missing account plan")
	}
	if !hasQuotaWindow(windows, "session") {
		return fmt.Errorf("missing session window")
	}
	if !hasQuotaWindow(windows, "weekly-all") && !hasQuotaWindow(windows, "weekly-sonnet") {
		return fmt.Errorf("missing weekly window")
	}
	return nil
}

func remainingPercent(used float64) int {
	if used < 0 {
		return 0
	}
	remaining := int(math.Round(100 - used))
	if remaining < 0 {
		return 0
	}
	if remaining > 100 {
		return 100
	}
	return remaining
}

func quotaRecord(windows []harnesses.QuotaWindow, metadata map[string]any) cassette.QuotaRecord {
	records := make([]map[string]any, 0, len(windows))
	for _, window := range windows {
		records = append(records, map[string]any{
			"name":           window.Name,
			"limit_id":       window.LimitID,
			"window_minutes": window.WindowMinutes,
			"used_percent":   window.UsedPercent,
			"resets_at":      window.ResetsAt,
			"state":          window.State,
		})
	}
	accountClass, _ := metadata["plan_type"].(string)
	return cassette.QuotaRecord{
		Source:            "pty",
		Status:            string(ptyquota.StatusOK),
		CapturedAt:        time.Now().UTC().Format(time.RFC3339),
		FreshnessWindow:   defaultClaudeQuotaStaleAfter.String(),
		StalenessBehavior: "stale quota evidence keeps Claude out of automatic routing and is treated as limited",
		AccountClass:      accountClass,
		Windows:           records,
		Metadata:          metadata,
	}
}

func accountPlan(account *harnesses.AccountInfo) string {
	if account == nil {
		return ""
	}
	return account.PlanType
}

func stringsJoinLines(lines []string) string {
	out := ""
	for i, line := range lines {
		if i > 0 {
			out += "\n"
		}
		out += line
	}
	return out
}

package claude

import (
	"context"
	"fmt"
	"os/exec"
	"regexp"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/ptyquota"
	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
)

const ClaudeModelDiscoveryFreshnessWindow = 24 * time.Hour

var (
	claudeFullModelPattern         = regexp.MustCompile(`\bclaude-[a-z0-9][a-z0-9._-]*\b`)
	claudeFullFamilyVersionPattern = regexp.MustCompile(`\bclaude-(sonnet|opus|haiku)-([0-9]+)[.-]([0-9]{1,2})(?:\b|-)`)
	claudeFamilyVersionPattern     = regexp.MustCompile(`\b(?:claude\s+)?(sonnet|opus|haiku)\s+([0-9]+(?:[.-][0-9]+){0,2})\b`)
	claudeAliasPattern             = regexp.MustCompile(`(?m)(?:^|[\s'"])(sonnet|opus|haiku)(?:$|[\s'"])`)
	claudeEffortPattern            = regexp.MustCompile(`--effort\s+<level>.*\(([^)]*)\)`)
)

func defaultClaudeModelDiscovery() harnesses.ModelDiscoverySnapshot {
	return harnesses.ModelDiscoverySnapshot{
		CapturedAt:      time.Now().UTC(),
		Models:          []string{"sonnet", "sonnet-4.6", "opus", "opus-4.7", "claude-sonnet-4-6"},
		ReasoningLevels: []string{"low", "medium", "high", "xhigh", "max"},
		Source:          "cli-help:claude",
		FreshnessWindow: ClaudeModelDiscoveryFreshnessWindow.String(),
		Detail:          "claude --help documents --model aliases/full IDs and --effort levels; authenticated PTY /model evidence refreshes family alias versions",
	}
}

func ReadClaudeModelDiscoveryViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (harnesses.ModelDiscoverySnapshot, error) {
	cfg := quotaPTYOptions{binary: "claude"}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	var snapshot harnesses.ModelDiscoverySnapshot
	_, err := ptyquota.Run(context.Background(), ptyquota.Config{
		HarnessName:  "claude",
		Binary:       cfg.binary,
		Args:         cfg.args,
		Workdir:      cfg.workdir,
		Env:          cfg.env,
		Command:      "/model\r",
		ReadyMarkers: []string{"❯", "> "},
		DoneWhen:     claudeModelDiscoveryComplete,
		Timeout:      timeout,
		Size:         session.Size{Rows: 50, Cols: 220},
		CassetteDir:  cfg.cassetteDir,
		Discovery: func(text string) (cassette.DiscoveryRecord, error) {
			snapshot = claudeDiscoveryFromText(text, "pty")
			if len(snapshot.Models) == 0 {
				return cassette.DiscoveryRecord{}, fmt.Errorf("no models found in claude /model output")
			}
			return discoveryRecord(snapshot), nil
		},
	})
	if err != nil {
		return harnesses.ModelDiscoverySnapshot{}, err
	}
	if len(snapshot.Models) == 0 {
		return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude /model output")
	}
	return snapshot, nil
}

func ReadClaudeModelDiscoveryFromCassette(dir string) (harnesses.ModelDiscoverySnapshot, error) {
	reader, err := cassette.Open(dir)
	if err != nil {
		return harnesses.ModelDiscoverySnapshot{}, err
	}
	if rec := reader.Discovery(); rec != nil && len(rec.Models) > 0 {
		return snapshotFromDiscoveryRecord(*rec), nil
	}
	text := reader.Final().FinalText
	if text == "" {
		frames := reader.Frames()
		if len(frames) > 0 {
			text = strings.Join(frames[len(frames)-1].Text, "\n")
		}
	}
	snapshot := claudeDiscoveryFromText(text, "cassette")
	if len(snapshot.Models) == 0 {
		return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude model cassette")
	}
	return snapshot, nil
}

func readClaudeReasoningFromHelp(ctx context.Context, binary string, args ...string) ([]string, error) {
	if binary == "" {
		binary = "claude"
	}
	if len(args) == 0 {
		args = []string{"--help"}
	}
	cmd := exec.CommandContext(ctx, binary, args...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("claude help: %w", err)
	}
	levels := parseClaudeReasoningLevels(string(out))
	if len(levels) == 0 {
		return nil, fmt.Errorf("claude help did not expose --effort levels")
	}
	return levels, nil
}

func claudeModelDiscoveryComplete(text string) bool {
	return len(parseClaudeModels(text)) > 0
}

func claudeDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
	snapshot := defaultClaudeModelDiscovery()
	if source != "" {
		snapshot.Source = source
	}
	if models := parseClaudeModels(text); len(models) > 0 {
		snapshot.Models = models
	}
	if levels := parseClaudeReasoningLevels(text); len(levels) > 0 {
		snapshot.ReasoningLevels = levels
	}
	return snapshot
}

func parseClaudeModels(text string) []string {
	text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
	lower := strings.ToLower(text)
	models := uniqueMatches(claudeFullModelPattern.FindAllString(lower, -1))
	for _, match := range claudeFullFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 3 {
			models = appendUniqueString(models, match[1]+"-"+match[2]+"."+match[3])
		}
	}
	for _, match := range claudeFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 2 {
			models = appendUniqueString(models, match[1]+"-"+strings.ReplaceAll(match[2], "-", "."))
		}
	}
	for _, match := range claudeAliasPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 1 {
			models = appendUniqueString(models, match[1])
		}
	}
	return models
}

func resolveClaudeFamilyAlias(model string, snapshot harnesses.ModelDiscoverySnapshot) string {
	family := strings.ToLower(strings.TrimSpace(model))
	if family != "sonnet" && family != "opus" && family != "haiku" {
		return model
	}
	if resolved := latestClaudeFamilyVersion(family, snapshot.Models); resolved != "" {
		return resolved
	}
	return model
}

func latestClaudeFamilyVersion(family string, models []string) string {
	prefix := family + "-"
	best := ""
	var bestParts []int
	for _, model := range models {
		model = strings.ToLower(strings.TrimSpace(model))
		if !strings.HasPrefix(model, prefix) {
			continue
		}
		parts, ok := parseClaudeVersionParts(strings.TrimPrefix(model, prefix))
		if !ok {
			continue
		}
		if best == "" || compareVersionParts(parts, bestParts) > 0 {
			best = model
			bestParts = parts
		}
	}
	return best
}

func parseClaudeVersionParts(version string) ([]int, bool) {
	version = strings.ReplaceAll(version, "-", ".")
	raw := strings.Split(version, ".")
	if len(raw) == 0 {
		return nil, false
	}
	parts := make([]int, 0, len(raw))
	for _, part := range raw {
		if part == "" {
			return nil, false
		}
		n := 0
		for _, r := range part {
			if r < '0' || r > '9' {
				return nil, false
			}
			n = n*10 + int(r-'0')
		}
		parts = append(parts, n)
	}
	return parts, true
}

func compareVersionParts(a, b []int) int {
	n := len(a)
	if len(b) > n {
		n = len(b)
	}
	for i := 0; i < n; i++ {
		av, bv := 0, 0
		if i < len(a) {
			av = a[i]
		}
		if i < len(b) {
			bv = b[i]
		}
		if av > bv {
			return 1
		}
		if av < bv {
			return -1
		}
	}
	return 0
}

func parseClaudeReasoningLevels(text string) []string {
	text = stripANSI(strings.ReplaceAll(text, "\n", " "))
	m := claudeEffortPattern.FindStringSubmatch(text)
	if len(m) < 2 {
		return nil
	}
	parts := strings.Split(m[1], ",")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		out = appendUniqueString(out, strings.TrimSpace(part))
	}
	return out
}

func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
	return cassette.DiscoveryRecord{
		Source:            snapshot.Source,
		Status:            string(ptyquota.StatusOK),
		Models:            append([]string(nil), snapshot.Models...),
		ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
		CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
		FreshnessWindow:   snapshot.FreshnessWindow,
		StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
		Metadata:          map[string]any{"detail": snapshot.Detail},
	}
}

func snapshotFromDiscoveryRecord(rec cassette.DiscoveryRecord) harnesses.ModelDiscoverySnapshot {
	capturedAt, _ := time.Parse(time.RFC3339, rec.CapturedAt)
	detail, _ := rec.Metadata["detail"].(string)
	return harnesses.ModelDiscoverySnapshot{
		CapturedAt:      capturedAt,
		Models:          append([]string(nil), rec.Models...),
		ReasoningLevels: append([]string(nil), rec.ReasoningLevels...),
		Source:          rec.Source,
		FreshnessWindow: rec.FreshnessWindow,
		Detail:          detail,
	}
}

func uniqueMatches(values []string) []string {
	out := make([]string, 0, len(values))
	for _, value := range values {
		out = appendUniqueString(out, value)
	}
	return out
}

func appendUniqueString(values []string, value string) []string {
	value = strings.TrimSpace(value)
	if value == "" {
		return values
	}
	for _, existing := range values {
		if existing == value {
			return values
		}
	}
	return append(values, value)
}

