1	package claude
2	
3	import (
4		"fmt"
5		"math"
6		"os"
7		"os/exec"
8		"regexp"
9		"strconv"
10		"strings"
11		"time"
12	
13		"github.com/easel/fizeau/internal/harnesses"
14	)
15	
16	var ansiPattern = regexp.MustCompile(`\x1b(?:\[[0-9;?]*[a-zA-Z]|[^[])`)
17	
18	func stripANSI(s string) string {
19		return ansiPattern.ReplaceAllString(s, "")
20	}
21	
22	// ReadClaudeQuotaViaTmux starts claude in a detached tmux session, sends /usage,
23	// captures the pane output, and returns parsed quota windows and account info.
24	//
25	// Deprecated: this is a diagnostic-only legacy path. Supported quota probes use
26	// ReadClaudeQuotaViaPTY so accepted evidence passes through direct PTY cassettes.
27	// Returns an error if tmux or claude are not found, or probing times out.
28	func ReadClaudeQuotaViaTmux(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
29		if _, err := exec.LookPath("tmux"); err != nil {
30			return nil, nil, fmt.Errorf("tmux not found in PATH: %w", err)
31		}
32		if _, err := exec.LookPath("claude"); err != nil {
33			return nil, nil, fmt.Errorf("claude not found in PATH: %w", err)
34		}
35		if timeout <= 0 {
36			timeout = 30 * time.Second
37		}
38	
39		sessName := fmt.Sprintf("ddx-claude-quota-%d", os.Getpid())
40		if err := exec.Command("tmux", "new-session", "-d", "-s", sessName, "-x", "220", "-y", "50", "claude").Run(); err != nil {
41			return nil, nil, fmt.Errorf("start tmux session: %w", err)
42		}
43		defer func() { _ = exec.Command("tmux", "kill-session", "-t", sessName).Run() }()
44	
45		// Poll until claude shows its interactive prompt (ready state).
46		// The prompt "❯" (or "> ") appears once the REPL is initialized.
47		deadline := time.Now().Add(timeout)
48		ready := false
49		for !ready && time.Now().Before(deadline) {
50			time.Sleep(500 * time.Millisecond)
51			// Bail early if the session has already exited (e.g. non-interactive binary).
52			if err := exec.Command("tmux", "has-session", "-t", sessName).Run(); err != nil {
53				return nil, nil, fmt.Errorf("claude session exited before initialization")
54			}
55			out, err := exec.Command("tmux", "capture-pane", "-t", sessName, "-p").Output()
56			if err == nil {
57				text := stripANSI(string(out))
58				// Look for the interactive prompt — appears when REPL is ready.
59				if strings.Contains(text, "❯") || strings.Contains(text, "> ") {
60					ready = true
61				}
62			}
63		}
64		if !ready {
65			return nil, nil, fmt.Errorf("timed out waiting for claude to initialize")
66		}
67	
68		if err := exec.Command("tmux", "send-keys", "-t", sessName, "/usage", "Enter").Run(); err != nil {
69			return nil, nil, fmt.Errorf("send /usage: %w", err)
70		}
71	
72		// Poll until usage data appears (look for "% used" and "Resets").
73		var captured string
74		for time.Now().Before(deadline) {
75			time.Sleep(500 * time.Millisecond)
76			out, err := exec.Command("tmux", "capture-pane", "-t", sessName, "-p", "-S", "-100").Output()
77			if err == nil {
78				text := stripANSI(string(out))
79				if strings.Contains(text, "% used") && strings.Contains(strings.ToLower(text), "resets") {
80					captured = text
81					break
82				}
83			}
84		}
85		if captured == "" {
86			return nil, nil, fmt.Errorf("timed out waiting for /usage output")
87		}
88	
89		windows, acct := parseClaudeUsageOutput(captured)
90		if len(windows) == 0 {
91			return nil, acct, fmt.Errorf("no quota windows found in /usage output")
92		}
93		return windows, acct, nil
94	}
95	
96	var (
97		claudeUsedPercentPattern        = regexp.MustCompile(`<?(\d+(?:\.\d+)?)%\s+used`)
98		claudePlanTypePattern           = regexp.MustCompile(`(?i)(Claude\s+(?:Max|Pro|Team|Enterprise|Free))`)
99		claudeStandalonePlanTypePattern = regexp.MustCompile(`(?i)\b(Max|Pro|Team|Enterprise|Free)\b(?:\s+plan)?`)
100	)
101	
102	type claudeUsageSection struct {
103		Name       string
104		LimitID    string
105		WindowMins int
106	}
107	
108	var claudeUsageSections = []claudeUsageSection{
109		{"Current session", "session", 300},
110		{"Current week (all models)", "weekly-all", 10080},
111		{"Current week (Sonnet only)", "weekly-sonnet", 10080},
112		{"Extra usage", "extra", 0},
113	}
114	
115	// parseClaudeUsageOutput parses text captured from a claude /usage pane.
116	// Returns quota windows and optional account info (plan type from header).
117	func parseClaudeUsageOutput(text string) ([]harnesses.QuotaWindow, *harnesses.AccountInfo) {
118		text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
119		lines := strings.Split(text, "\n")
120	
121		var acct *harnesses.AccountInfo
122		var windows []harnesses.QuotaWindow
123	
124		// Extract plan type from header line.
125		for _, line := range lines {
126			if m := claudePlanTypePattern.FindString(line); m != "" {
127				acct = &harnesses.AccountInfo{PlanType: normalizeClaudePlanType(m)}
128				break
129			}
130			if m := claudeStandalonePlanTypePattern.FindStringSubmatch(line); len(m) > 1 {
131				acct = &harnesses.AccountInfo{PlanType: normalizeClaudePlanType(m[1])}
132				break
133			}
134		}
135	
136		// Walk lines looking for section headers, then harvest % used and Resets.
137		for i, line := range lines {
138			trimmed := strings.TrimSpace(line)
139			trimmedLower := strings.ToLower(trimmed)
140	
141			var sec *claudeUsageSection
142			for j := range claudeUsageSections {
143				if trimmedLower == strings.ToLower(claudeUsageSections[j].Name) {
144					sec = &claudeUsageSections[j]
145					break
146				}
147			}
148			if sec == nil {
149				continue
150			}
151	
152			// Scan ahead up to 5 lines for "% used" then "Resets".
153			var usedPct float64
154			var resetsAt string
155			found := false
156	
157			for j := i + 1; j < len(lines) && j <= i+5; j++ {
158				next := strings.TrimSpace(lines[j])
159				if !found {
160					if m := claudeUsedPercentPattern.FindStringSubmatch(next); m != nil {
161						pct, _ := strconv.ParseFloat(m[1], 64)
162						usedPct = pct
163						found = true
164					}
165				}
166				if found && resetsAt == "" && strings.Contains(strings.ToLower(next), "resets") {
167					resetsAt = extractResetsText(next)
168				}
169				if found && resetsAt != "" {
170					break
171				}
172			}
173	
174			if !found {
175				continue
176			}
177	
178			windows = append(windows, harnesses.QuotaWindow{
179				Name:          sec.Name,
180				LimitID:       sec.LimitID,
181				WindowMinutes: sec.WindowMins,
182				UsedPercent:   usedPct,
183				ResetsAt:      resetsAt,
184				State:         harnesses.QuotaStateFromUsedPercent(int(math.Ceil(usedPct))),
185			})
186		}
187	
188		return windows, acct
189	}
190	
191	func normalizeClaudePlanType(plan string) string {
192		plan = strings.TrimSpace(plan)
193		if plan == "" {
194			return ""
195		}
196		if strings.HasPrefix(strings.ToLower(plan), "claude ") {
197			return plan
198		}
199		return "Claude " + plan
200	}
201	
202	// extractResetsText strips the "Resets" prefix from a line.
203	// Handles: "Resets 4pm (America/New_York)"
204	//
205	//	"$200 spent · Resets May 1 (America/New_York)"
206	func extractResetsText(line string) string {
207		lower := strings.ToLower(line)
208		idx := strings.Index(lower, "resets")
209		if idx < 0 {
210			return ""
211		}
212		return strings.TrimSpace(line[idx+len("resets"):])
213	}
