172	func collectClaudeSignal(sig *Signal) {
173		snap, ok := claudecache.ReadClaudeQuota()
174		if !ok || snap == nil {
175			return // StatusUnknown
176		}
177		if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
178			return // StatusUnknown; snapshot is stale
179		}
180		if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
181			sig.Status = StatusExhausted
182			zero := 0
183			sig.QuotaRemaining = &zero
184			return
185		}
186		sig.Status = StatusAvailable
187		rem := snap.FiveHourRemaining
188		sig.QuotaRemaining = &rem
189	}
190	
191	func collectCodexSignal(sig *Signal) {
192		snap, ok := codexcache.ReadCodexQuota()
193		if !ok || snap == nil {
194			return // StatusUnknown
195		}
196		if codexcache.CodexQuotaSnapshotAge(snap, time.Now()) > codexcache.DefaultCodexQuotaStaleAfter {
197			return // StatusUnknown; snapshot is stale
198		}
199		for _, w := range snap.Windows {
200			if w.UsedPercent >= 95 || w.State == "blocked" {
201				sig.Status = StatusExhausted
202				zero := 0
203				sig.QuotaRemaining = &zero
204				return
205			}
206		}
207		sig.Status = StatusAvailable
208	}
