228	// collectHeaderSignal reads the most recently recorded rate-limit header signal
229	// for the provider and populates sig accordingly.
230	func (s *Store) collectHeaderSignal(providerName string, sig *Signal) {
231		hSig, ok := s.headers.get(providerName)
232		if !ok {
233			return // StatusUnknown; no headers observed yet
234		}
235		exhausted, retryAfter := hSig.IsExhausted(time.Now())
236		if exhausted {
237			sig.Status = StatusExhausted
238			zero := 0
239			sig.QuotaRemaining = &zero
240			if !retryAfter.IsZero() {
241				t := retryAfter
242				sig.QuotaResetAt = &t
243			}
244			return
245		}
246		sig.Status = StatusAvailable
247		switch {
248		case hSig.RemainingRequests >= 0:
249			rem := int(hSig.RemainingRequests)
250			sig.QuotaRemaining = &rem
251		case hSig.RemainingTokens >= 0:
252			rem := int(hSig.RemainingTokens)
253			sig.QuotaRemaining = &rem
254		}
255		if !hSig.ResetTime.IsZero() {
256			t := hSig.ResetTime
257			sig.QuotaResetAt = &t
258		}
259	}
