8	// atomicWrite writes data to path using the tmp→fsync→rename pattern so
9	// readers never observe a partial write. Mirrors the pattern in
10	// internal/harnesses/claude/quota_cache.go:WriteClaudeQuota.
11	func atomicWrite(path string, data []byte) error {
12		if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
13			return err
14		}
15		tmp := path + ".tmp"
16		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0o600) // #nosec G304
17		if err != nil {
18			return err
19		}
20		if _, werr := f.Write(data); werr != nil {
21			_ = f.Close()
22			_ = os.Remove(tmp)
23			return werr
24		}
25		if serr := f.Sync(); serr != nil {
26			_ = f.Close()
27			_ = os.Remove(tmp)
28			return serr
29		}
30		if cerr := f.Close(); cerr != nil {
31			_ = os.Remove(tmp)
32			return cerr
33		}
34		if rerr := os.Rename(tmp, path); rerr != nil {
35			_ = os.Remove(tmp)
36			return rerr
37		}
38		_ = os.Chmod(path, 0o600) // best-effort: ensure mode even if older file existed
39		return nil
40	}
