// ReadQuotaAvailability reports claude quota availability from the durable cache.
// Returns (false, false, 0, false) when no fresh snapshot exists.
// Bridge for internal/runtimesignals until BEAD-HARNESS-IF-09 migrates it.
func ReadQuotaAvailability(now time.Time) (available, exhausted bool, fiveHourRemaining int, ok bool) {
	snap, snapOK := readClaudeQuota()
	if !snapOK || snap == nil {
		return false, false, 0, false
	}
	if claudeQuotaSnapshotAge(snap, now) > defaultClaudeQuotaStaleAfter {
		return false, false, 0, false
	}
	if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
		return false, true, snap.FiveHourRemaining, true
	}
	return true, false, snap.FiveHourRemaining, true
}

// QuotaSnapshot is an exported alias for claudeQuotaSnapshot so that callers
// outside this package can construct and inspect quota cache entries.
// Bridge type until BEAD-HARNESS-IF-09 migrates external callers.
type QuotaSnapshot = claudeQuotaSnapshot

// WriteQuotaSnapshot atomically persists a QuotaSnapshot to the given path.
// Bridge for external callers (service tests, runtimesignals) until
// BEAD-HARNESS-IF-09 migrates them to the QuotaHarness interface.
func WriteQuotaSnapshot(path string, snapshot QuotaSnapshot) error {
	return writeClaudeQuota(path, snapshot)
}

