func collectClaudeSignal(sig *Signal) {
	available, exhausted, fiveHourRemaining, ok := claudecache.ReadQuotaAvailability(time.Now())
	if !ok {
		return // StatusUnknown; no fresh snapshot
	}
	if exhausted {
		sig.Status = StatusExhausted
		zero := 0
		sig.QuotaRemaining = &zero
		return
	}
	if available {
		sig.Status = StatusAvailable
		rem := fiveHourRemaining
		sig.QuotaRemaining = &rem
	}
}

